<template><div class="page-wrap"><section class="page-hero"><div><span class="eyebrow">MEDICAL STAFF</span><h1>医生管理</h1><p>统一维护医生账号、所属科室、职称与专业信息</p></div><div class="hero-count"><span>医生总数</span><strong>{{total}}</strong></div></section><section class="content-card"><div class="card-toolbar"><div><h2>医生档案</h2><p>支持添加账号、重置密码和安全删除</p></div><div class="toolbar-actions"><el-input v-model="keyword" :prefix-icon="Search" placeholder="搜索姓名或账号" clearable/><el-select v-model="departmentFilter" placeholder="全部科室" clearable><el-option v-for="d in departments" :key="d.id" :label="d.name" :value="d.id"/></el-select><el-button class="soft-btn" :icon="Refresh" @click="loadData">刷新</el-button><el-button type="primary" class="primary-btn" :icon="Plus" @click="openAdd">添加医生</el-button></div></div><el-table :data="filtered" v-loading="loading" class="admin-table"><el-table-column label="医生" min-width="190"><template #default="{row}"><div class="doctor-cell"><span>{{row.name?.slice(0,1)}}</span><div><strong>{{row.name}}</strong><small>@{{row.username}}</small></div></div></template></el-table-column><el-table-column prop="departmentName" label="所属科室" min-width="140"><template #default="{row}"><el-tag type="success" effect="light" round>{{row.departmentName||'未分配'}}</el-tag></template></el-table-column><el-table-column prop="title" label="职称" min-width="130"><template #default="{row}">{{row.title||'暂未设置'}}</template></el-table-column><el-table-column prop="phone" label="联系电话" min-width="140"><template #default="{row}"><span class="muted">{{row.phone||'--'}}</span></template></el-table-column><el-table-column prop="specialty" label="擅长领域" min-width="220" show-overflow-tooltip><template #default="{row}">{{row.specialty||'暂未填写'}}</template></el-table-column><el-table-column label="操作" width="190" fixed="right"><template #default="{row}"><el-button link type="warning" @click="resetPwd(row)">重置密码</el-button><el-button link type="danger" @click="remove(row)">删除</el-button></template></el-table-column></el-table><div class="pagination-bar"><span>共 {{total}} 位医生</span><el-pagination v-model:current-page="page" :page-size="size" :total="total" layout="prev,pager,next" @current-change="loadData"/></div></section><el-dialog v-model="dialog" title="添加医生账号" width="620px" destroy-on-close><el-form ref="formRef" :model="form" :rules="rules" label-position="top" class="dialog-form"><div class="form-grid"><el-form-item label="登录账号" prop="username"><el-input v-model="form.username" placeholder="至少3位"/></el-form-item><el-form-item label="初始密码"><el-input v-model="form.password" type="password" show-password placeholder="不填则为123456"/></el-form-item><el-form-item label="医生姓名" prop="name"><el-input v-model="form.name"/></el-form-item><el-form-item label="联系电话"><el-input v-model="form.phone" maxlength="11"/></el-form-item><el-form-item label="所属科室" prop="departmentId"><el-select v-model="form.departmentId" style="width:100%" @change="changeDept"><el-option v-for="d in departments" :key="d.id" :label="d.name" :value="d.id"/></el-select></el-form-item><el-form-item label="职称"><el-select v-model="form.title" style="width:100%"><el-option v-for="t in titles" :key="t" :label="t" :value="t"/></el-select></el-form-item><el-form-item label="擅长领域" class="span-two"><el-input v-model="form.specialty" maxlength="100"/></el-form-item></div></el-form><template #footer><el-button @click="dialog=false">取消</el-button><el-button type="primary" class="primary-btn" :loading="saving" @click="save">创建账号</el-button></template></el-dialog></div></template>
<script setup lang="ts">
import{computed,onMounted,reactive,ref}from'vue';import{ElMessage,ElMessageBox,type FormInstance,type FormRules}from'element-plus';import{Plus,Search,Refresh}from'@element-plus/icons-vue';import{addDoctor,deleteDoctor,getDoctorPage,resetDoctorPassword}from'@/api/doctor';import{getDepartments}from'@/api/department';import type{Department,Doctor}from'@/types';const loading=ref(false),saving=ref(false),dialog=ref(false),page=ref(1),size=ref(10),total=ref(0),keyword=ref(''),departmentFilter=ref<number>(),list=ref<Doctor[]>([]),departments=ref<Department[]>([]),formRef=ref<FormInstance>();const titles=['住院医师','主治医师','副主任医师','主任医师'];const form=reactive<Doctor>({username:'',password:'',name:'',phone:'',departmentId:undefined,departmentName:'',title:'',specialty:''});const rules:FormRules={username:[{required:true,message:'请输入登录账号',trigger:'blur'},{min:3,message:'账号至少3位',trigger:'blur'}],name:[{required:true,message:'请输入医生姓名',trigger:'blur'}],departmentId:[{required:true,message:'请选择科室',trigger:'change'}]};const filtered=computed(()=>list.value.filter(d=>(!keyword.value||d.name?.includes(keyword.value.trim())||d.username.includes(keyword.value.trim()))&&(!departmentFilter.value||d.departmentId===departmentFilter.value)));const loadData=async()=>{loading.value=true;try{const r=await getDoctorPage(page.value,size.value);list.value=r.data.data.content;total.value=r.data.data.totalElements}finally{loading.value=false}};const openAdd=()=>{Object.assign(form,{username:'',password:'',name:'',phone:'',departmentId:undefined,departmentName:'',title:'',specialty:''});dialog.value=true};const changeDept=(id:number)=>{form.departmentName=departments.value.find(d=>d.id===id)?.name||''};const save=async()=>{if(!await formRef.value?.validate().catch(()=>false))return;saving.value=true;try{await addDoctor({...form});ElMessage.success('医生账号创建成功');dialog.value=false;loadData()}finally{saving.value=false}};const resetPwd=async(row:Doctor)=>{await ElMessageBox.confirm(`确认将“${row.name}”的密码重置为 123456 吗？`,'重置密码',{type:'warning'});await resetDoctorPassword(row.id!);ElMessage.success('密码已重置为123456')};const remove=async(row:Doctor)=>{await ElMessageBox.confirm(`确定删除医生“${row.name}”吗？存在未完成挂号时将无法删除。`,'删除医生',{type:'warning'});await deleteDoctor(row.id!);ElMessage.success('医生已删除');loadData()};onMounted(async()=>{departments.value=(await getDepartments()).data.data;loadData()})
</script>
<style scoped>.hero-count{position:relative;z-index:2;min-width:130px;padding:13px 18px;border:1px solid rgba(255,255,255,.17);border-radius:14px;background:rgba(255,255,255,.1)}.hero-count span,.hero-count strong{display:block}.hero-count span{font-size:9px;opacity:.6}.hero-count strong{margin-top:3px;font-size:25px}.doctor-cell{display:flex;align-items:center;gap:11px}.doctor-cell>span{width:39px;height:39px;display:flex;align-items:center;justify-content:center;border-radius:12px;background:linear-gradient(145deg,#dcefee,#bee0dc);color:#087f84;font-weight:800}.doctor-cell strong,.doctor-cell small{display:block}.doctor-cell small{margin-top:3px;color:#99a8ad;font-size:9px}.form-grid{display:grid;grid-template-columns:1fr 1fr;gap:0 20px}.span-two{grid-column:1/-1}</style>
